const AccordionContext = React.createContext();

export function Accordion({ children }) {
  const [openIndex, setOpenIndex] = React.useState(null);

  const value = {
    openIndex,
    setOpenIndex,
  };

  return (
    <AccordionContext.Provider value={value}>
      <div className="accordion">{children}</div>
    </AccordionContext.Provider>
  );
}

export function AccordionItem({ index, children }) {
  return <div className="item">{React.Children.map(children, child => 
    React.cloneElement(child, { index })
  )}</div>;
}

export function AccordionHeader({ index, children }) {
  const { openIndex, setOpenIndex } = React.useContext(AccordionContext);
  const isOpen = openIndex === index;

  return (
    <div
      className="header"
      onClick={() => setOpenIndex(isOpen ? null : index)}
    >
      {children}
    </div>
  );
}

export function AccordionPanel({ index, children }) {
  const { openIndex } = React.useContext(AccordionContext);
  const isOpen = openIndex === index;

  return isOpen ? <div className="panel">{children}</div> : null;
}
