  const [internalOn, setInternalOn] = useState(false);

  // Если проп "on" передан — используем его, иначе внутреннее состояние
  const isControlled = controlledOn !== undefined;
  const on = isControlled ? controlledOn : internalOn;

  const toggle = () => {
    const newState = !on;
    if (!isControlled) setInternalOn(newState); // внутреннее управление
    onChange?.(newState);                       // уведомляем внешний мир
  };

  return <button onClick={toggle}>{on ? "ON" : "OFF"}</button>;
}
